messages.content:
Para configurar uma stack completa de observabilidade no OCI via Terraform:

1. **Módulo de Logging**:
```hcl
resource "oci_logging_log_group" "observability_log_group" {
  compartment_id = var.compartment_ocid
  display_name   = "observability-log-group"
}

resource "oci_logging_log" "service_logs" {
  display_name = "service-logs"
  log_group_id = oci_logging_log_group.observability_log_group.id
  is_enabled   = true
  log_type     = "SERVICE"
  configuration {
    source {
      category    = "all"
      source_type = "OCISERVICE"
    }
  }
  retention_duration = 30
}

resource "oci_logging_log" "custom_app_logs" {
  display_name = "custom-app-logs"
  log_group_id = oci_logging_log_group.observability_log_group.id
  is_enabled   = true
  log_type     = "CUSTOM"
  configuration {
    source {
      category    = "application"
      source_type = "CUSTOM"
    }
  }
  retention_duration = 90
}
```

2. **Módulo de Monitoring**:
```hcl
resource "oci_monitoring_alarm" "infrastructure_alarms" {
  for_each = {
    cpu    = { metric = "CpuUtilization", threshold = 85, severity = "CRITICAL" }
    memory = { metric = "MemoryUtilization", threshold = 90, severity = "CRITICAL" }
    disk   = { metric = "DiskUtilization", threshold = 85, severity = "WARNING" }
  }

  compartment_id      = var.compartment_ocid
  display_name        = "${each.key}-threshold-alarm"
  is_enabled          = true
  metric_compartment_id = var.compartment_ocid
  namespace           = "oci_computeagent"
  metric_name         = each.value.metric
  statistic           = "MAX"
  interval            = "5m"
  threshold           = each.value.threshold
  pending_duration    = "PT5M"
  severity            = each.value.severity

  destinations {
    service_type = "ONS"
    topic_id     = oci_ons_notification_topic.observability_topic.id
  }
}
```

3. **Módulo de APM**:
```hcl
resource "oci_apm_apm_domain" "observability_apm" {
  compartment_id = var.compartment_ocid
  display_name   = "observability-apm-domain"
}

resource "oci_functions_application" "traced_functions" {
  compartment_id = var.compartment_ocid
  display_name   = "traced-fn-app"
  subnet_ids     = [var.subnet_ocid]

  trace_config {
    domain_id  = oci_apm_apm_domain.observability_apm.id
    is_enabled = true
  }
}
```

4. **Módulo de Notifications**:
```hcl
resource "oci_ons_notification_topic" "observability_topic" {
  compartment_id = var.compartment_ocid
  name           = "observability-alerts"
}

resource "oci_ons_subscription" "pagerduty_subscriber" {
  compartment_id = var.compartment_ocid
  topic_id       = oci_ons_notification_topic.observability_topic.id
  protocol       = "CUSTOM_HTTPS"
  endpoint       = "https://events.pagerduty.com/integration/xxx/enqueue"
}
```

5. **Outputs**:
```hcl
output "apm_domain_id" {
  value = oci_apm_apm_domain.observability_apm.id
}

output "notification_topic_id" {
  value = oci_ons_notification_topic.observability_topic.id
}

output "log_group_id" {
  value = oci_logging_log_group.observability_log_group.id
}
```

6. **Arquitetura resultante**:
```
Instâncias → OCI Logging Agent → Log Group → Saved Searches
    ↓
OCI Monitoring Agent → Métricas → Alarms → ONS → PagerDuty/Email
    ↓
APM Agent → APM Domain → Traces/Metrics
    ↓
Functions → Trace Config → APM Domain
```

[MUTABLE] Os custos de cada serviço variam por volume e região.

Ref: https://docs.oracle.com/en-us/iaas/Content/observability.htm
